"use client";
import Image from "next/image";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { ReactNode, useEffect, useRef, useState } from "react";

export function LanguageSwitcher(){
 const [language,setLanguage]=useState<"vi"|"en">("vi");
 useEffect(()=>{const saved=localStorage.getItem("prewise-language");const next=saved==="en"?"en":"vi";setLanguage(next);document.documentElement.lang=next},[]);
 function select(next:"vi"|"en"){setLanguage(next);localStorage.setItem("prewise-language",next);document.documentElement.lang=next}
 return <div className="language-switcher" role="group" aria-label="Chọn ngôn ngữ / Choose language"><button type="button" className={language==="vi"?"active":""} aria-pressed={language==="vi"} onClick={()=>select("vi")}>VI</button><span aria-hidden>/</span><button type="button" className={language==="en"?"active":""} aria-pressed={language==="en"} onClick={()=>select("en")}>EN</button></div>
}

export function PrewiseShell({children}:{children:ReactNode}){
 const path=usePathname(); const [open,setOpen]=useState(false); const menu=useRef<HTMLDivElement>(null);
 useEffect(()=>{const close=(e:MouseEvent)=>{if(menu.current&&!menu.current.contains(e.target as Node))setOpen(false)};document.addEventListener("mousedown",close);return()=>document.removeEventListener("mousedown",close)},[]);
 return <div className="app-ui"><a className="skip-link" href="#main-content">Bỏ qua đến nội dung chính</a><header className="app-top"><Link href="/" className="brand"><Image src="/prewise-logo.png" width={34} height={34} alt="Prewise"/><b>PREWISE</b></Link><nav aria-label="Điều hướng ứng dụng"><Link aria-current={path==="/analyze"?"page":undefined} className={path==="/analyze"?"active":""} href="/analyze">Phân tích</Link><Link aria-current={path==="/history"?"page":undefined} className={path==="/history"?"active":""} href="/history">Lịch sử</Link><Link aria-current={path==="/methodology"?"page":undefined} className={path==="/methodology"?"active":""} href="/methodology">Minh bạch</Link></nav><div className="app-tools"><LanguageSwitcher/><span className="privacy-pill">● Lịch sử cục bộ</span><Link href="/settings" aria-label="Cài đặt">⚙</Link><div ref={menu} className="profile-menu"><button type="button" onClick={()=>setOpen(v=>!v)} aria-expanded={open} aria-haspopup="menu" aria-label="Mở menu tài khoản">ND</button>{open&&<div className="profile-popover" role="menu"><Link href="/account">Tài khoản</Link><Link href="/account/api-key">API key</Link><Link href="/account/billing">Gói dịch vụ</Link><Link href="/settings">Cài đặt</Link><Link href="/">Về trang chủ</Link></div>}</div></div></header>{children}</div>
}

export function RiskDial({score}:{score:number}){const level=score>=85?"Nghiêm trọng":score>=70?"Cao":score>=40?"Trung bình":score>=15?"Thấp":"An toàn";return <div className="risk-dial" style={{"--score":`${score*3.6}deg`} as React.CSSProperties}><div><strong>{score}</strong><small>/100</small></div><span>{level}</span></div>}
export type Finding={title:string;detail:string;severity:"high"|"medium"|"low";evidence:string};
export const demoFindings:Finding[]=[{title:"Tên miền có dấu hiệu giả mạo",detail:"Tên miền sử dụng ký tự và cấu trúc gần giống một dịch vụ tài chính đáng tin cậy.",severity:"high",evidence:"secure-paypaI-support.com"},{title:"Tạo cảm giác khẩn cấp",detail:"Nội dung thúc ép người nhận hành động ngay để tránh khóa tài khoản.",severity:"medium",evidence:"xác minh trong vòng 30 phút"},{title:"Yêu cầu dữ liệu nhạy cảm",detail:"Biểu mẫu đích yêu cầu thông tin đăng nhập và mã xác thực.",severity:"high",evidence:"password • OTP • card details"}];
export function useLocalHistory(){const [items,setItems]=useState<any[]>([]);useEffect(()=>{try{setItems(JSON.parse(localStorage.getItem("prewise-history")||"[]"))}catch{setItems([])}},[]);return items}
